// ─── Types ────────────────────────────────────────────────────────────────────
interface Photo {
  id: number;
  src: string;
  caption: string;
  aspectRatio: "portrait" | "landscape" | "square";
}

interface GalleryEvent {
  id: number;
  category: string;
  title: string;
  date: string;
  location: string;
  description: string;
  photoCount: number;
  coverBg: string;
  accent: string;
  span: "tall" | "wide" | "normal" | "large";
  photos: Photo[];
}

